require"UI.UIBase"require"UI.UIBlock"UI_Activity_Guide=UIBase:Inherit()function UI_Activity_Guide:OnCreate()UI_Activity_Guide.Inst=self;self.animation_self=self.dialogue_self:GetComponent(typeof(UnityEngine.Animation))self.animation_chara=self.dialogue_chara:GetComponent(typeof(UnityEngine.Animation))self.canvasgroup_self=self.dialogue_self:GetComponent(typeof(UnityEngine.CanvasGroup))self.canvasgroup_chara=self.dialogue_chara:GetComponent(typeof(UnityEngine.CanvasGroup))end;function UI_Activity_Guide:Show(a,b,c)self.activity_id=a;self.finish_callback=b;self.show_cg=c or false;self:Init()self.locking=true;self.transform.gameObject:SetActive(true)self:AnimAlphaIn(self.transform,{x=0,y=0},0.2,0,function()self.locking=false end)end;function UI_Activity_Guide:Init()if not self.activity_id then self:Close()return end;self.guide_cfg={}local d=ExcelMgr.GetTable("activity","activity_guide")if not d then LogTool.Error("UI_Activity_Guide:Init","activity_guide data not found")self:Close()return end;for e,f in pairs(d)do if f and f.activity_id==self.activity_id then table.insert(self.guide_cfg,f)end end;table.sort(self.guide_cfg,function(g,h)return g.guide_id<h.guide_id end)self.cur_page=1;self.total_page=#self.guide_cfg;self:RefreshPage()end;function UI_Activity_Guide:RefreshPage()self.locking=true;TimeMgr.Delay(0.3,function()self.locking=false end)local i=self.guide_cfg[self.cur_page].guide_location==0;if self.canvasgroup_self.alpha~=0 then self.animation_self:Play("UI_Activity_Guide_Self2")end;if self.canvasgroup_chara.alpha~=0 then self.animation_chara:Play("UI_Activity_Guide_Chara2")end;TimeMgr.Delay(0.15,function()if i then self.text_self_name.text=self.guide_cfg[self.cur_page].char_str_id==0 and GameMgr.Inst.account_data.nickname or Tools.EventStrOfLocalization(self.guide_cfg[self.cur_page].char_str_id)self.text_self_talk.text=Tools.EventStrOfLocalization(self.guide_cfg[self.cur_page].content_str_id)self.animation_self:Play("UI_Activity_Guide_Self1")else local j=GameUtility.get_item_view(self.guide_cfg[self.cur_page].char_id)if j then self.text_chara_name.text=j.name end;self.text_chara_talk.text=Tools.EventStrOfLocalization(self.guide_cfg[self.cur_page].content_str_id)self.animation_chara:Play("UI_Activity_Guide_Chara1")end end)end;function UI_Activity_Guide:OnClick()if self.locking then return end;if self.cur_page<self.total_page then self.cur_page=self.cur_page+1;self:RefreshPage()else if self.show_cg then self.show_cg=false;if self.canvasgroup_self.alpha~=0 then self.animation_self:Play("UI_Activity_Guide_Self2")end;if self.canvasgroup_chara.alpha~=0 then self.animation_chara:Play("UI_Activity_Guide_Chara2")end;self.locking=true;TimeMgr.Delay(0.15,function()self.img_cg.gameObject:SetActive(true)end)TimeMgr.Delay(0.3,function()self.locking=false end)else if self.finish_callback then local k=self.finish_callback;self.finish_callback=nil;k()end;self:Close()end end end;function UI_Activity_Guide:Close()if self.locking then return end;self.locking=true;self:AnimAlphaOut(self.transform,{x=0,y=0},0.2,0,function()self.locking=false;self.transform.gameObject:SetActive(false)self.img_cg.gameObject:SetActive(false)end)end;return UI_Activity_Guide